#!/bin/python3

# Importing necessary modules
import logging, time
from datetime import datetime  # to provide access to the current date and time


# To log information and errors
# Logs are in a specific format and are stored at /root/.logs.
logging.basicConfig(filename="/root/.logs/log",
                    level=logging.DEBUG, 
                    format="%(asctime)s %(message)s")



def logger():
    """
    Method logger() runs every 2 minutes
    and writes to log file, the current 
    date and time (in hh:mm:ss format), 
    and 11th character from hello world string.

    Logs are in a specific format and 
    are stored at /root/.logs.
    """

    print("\nEntering Method: logger()")

    # To provide access to the current date and time
    current_date = datetime.now().strftime("%Y-%m-%d %H:%M:%S")


    print("current_time:",  current_date)
    print("Hello world  :", hello())
    
    logging.debug(hello())

    return True


def hello():  
    """
    Function hello() returns the character at index 10 
    of a hello world string.
    """
  
    # Returning the 11th character from 'Hello world'
    return "Hello world"[10]


if __name__ == "__main__":
    
    print("\nEntering Main")

    logger_return = True
    while logger_return:
        try:
            time.sleep(2)
            print(logger())
            #time.sleep(300)   # 5 minutes * 60 seconds = 300 seconds
        except Exception as err:   
            print("\nException is ", str(err))